/**
 * Attach the Fancy Product Designer preview (_fpd_product_thumbnail) to emails.
 * - Outlook/Kadence can't block attachments
 * - Admin "new_order" only by default (keep customer emails lean)
 */
add_filter('woocommerce_email_attachments', function ($attachments, $email_id, $order, $email) {

    if ( ! $order instanceof WC_Order ) return $attachments;

    // Send attachments only for these email IDs:
    $target_email_ids = [
        'new_order', // Admin
        // 'customer_processing_order', // ← Uncomment to send to customers
        // 'customer_completed_order',
    ];
    if ( ! in_array( $email_id, $target_email_ids, true ) ) return $attachments;

    $uploads   = wp_upload_dir();
    $baseurl   = rtrim($uploads['baseurl'], '/');
    $basedir   = rtrim($uploads['basedir'], DIRECTORY_SEPARATOR);
    $store_dir = trailingslashit($basedir) . 'fpd-email-attachments';
    wp_mkdir_p($store_dir);

    $max_attachments = 6;

    foreach ($order->get_items() as $item_id => $item) {
        if (count($attachments) >= $max_attachments) break;
        if (!$item instanceof WC_Order_Item_Product) continue;

        $url = $item->get_meta('_fpd_product_thumbnail', true);
        if (!is_string($url) || !preg_match('#^https?://#i', $url)) continue;

        $path = null;

        // 1) If URL lives under /uploads, map to local path (no download).
        if (stripos($url, $baseurl) === 0) {
            $rel  = ltrim(substr($url, strlen($baseurl)), '/');
            $cand = $basedir . DIRECTORY_SEPARATOR . str_replace('/', DIRECTORY_SEPARATOR, $rel);
            if (file_exists($cand) && is_readable($cand)) $path = $cand;
        }

        // 2) Fallback: download to uploads if mapping didn't work.
        if (!$path && function_exists('download_url')) {
            $tmp = download_url($url, 20);
            if (!is_wp_error($tmp) && file_exists($tmp)) {
                $ext = 'jpg';
                if (preg_match('/\.(png)(\?.*)?$/i', $url)) $ext = 'png';
                elseif (preg_match('/\.(jpe?g)(\?.*)?$/i', $url)) $ext = 'jpg';

                $dest = trailingslashit($store_dir) . wp_unique_filename(
                    $store_dir,
                    'order' . $order->get_id() . '-item' . $item_id . '.' . $ext
                );
                $moved = @rename($tmp, $dest);
                if (!$moved) { @copy($tmp, $dest); @unlink($tmp); }
                if (file_exists($dest)) $path = $dest;
            }
        }

        if ($path) $attachments[] = $path;
    }

    return $attachments;

}, 10, 4);

add_action('wp_footer', function () {
  if (!function_exists('is_product') || !is_product()) return;
  ?>
  <script>
  (function(){
    const PREFIX = '__overlay_';

    function getLabelText(cell) {
      // The label is the first text node inside .fpd-cell-1
      // e.g. "__overlay_highlight" before the <div class="fpd-img-meta">
      for (const node of cell.childNodes) {
        if (node.nodeType === Node.TEXT_NODE) {
          return (node.textContent || '').trim();
        }
      }
      // Fallback
      return (cell.textContent || '').trim();
    }

    function removeOverlayRows() {
      // This is the exact container shown in your HTML
      const manageLayers = document.querySelector('fpd-module-manage-layers');
      if (!manageLayers) return;

      const rows = manageLayers.querySelectorAll('.fpd-list-row');
      rows.forEach(row => {
        const cell = row.querySelector('.fpd-cell-1');
        if (!cell) return;

        const label = getLabelText(cell);
        if (label.startsWith(PREFIX)) {
          row.remove(); // remove the entire row from the list
        }
      });
    }

    // Run after load + re-run because FPD re-renders panels dynamically
    function runBurst() {
      removeOverlayRows();
      setTimeout(removeOverlayRows, 200);
      setTimeout(removeOverlayRows, 600);
      setTimeout(removeOverlayRows, 1200);
    }

    document.addEventListener('DOMContentLoaded', runBurst);

    // Watch for re-renders and re-remove the rows
    const obs = new MutationObserver(() => removeOverlayRows());
    obs.observe(document.body, { childList: true, subtree: true });

    // When user clicks around / opens Manage Design, run again shortly after
    document.addEventListener('click', () => {
      setTimeout(removeOverlayRows, 50);
      setTimeout(removeOverlayRows, 250);
    }, true);

  })();
  </script>
  <?php
}, 999);

add_action('wp_footer', function () {
  if (!function_exists('is_product') || !is_product()) return;
  ?>
  <script>
  document.addEventListener('DOMContentLoaded', function() {

    function forceAdvancedPicker() {

      const pickers = document.querySelectorAll('.picker_wrapper');

      pickers.forEach(function(picker) {

        // Ensure full layout class is applied
        picker.classList.remove('layout_block');
        picker.classList.add('layout_default');

        // Ensure sliders are visible
        const hue = picker.querySelector('.picker_hue');
        const sl = picker.querySelector('.picker_sl');
        const alpha = picker.querySelector('.picker_alpha');

        if (hue) hue.style.display = 'block';
        if (sl) sl.style.display = 'block';
        if (alpha) alpha.style.display = 'block';
      });

    }

    // Run multiple times because FPD builds dynamically
    setTimeout(forceAdvancedPicker, 300);
    setTimeout(forceAdvancedPicker, 800);
    setTimeout(forceAdvancedPicker, 1500);

    const observer = new MutationObserver(forceAdvancedPicker);
    observer.observe(document.body, { childList: true, subtree: true });

  });
  </script>
  <?php
}, 999);

